using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.ApiTests;/// <summary>/// Good case: Get EHR records for organization with valid org ID/// Expected: 200 OK with records list/// </summary>public class EhrServiceTests_GetOrgEhrRecords_WithValidOrgId_ShouldReturnRecords : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "EhrService"    };    [SkippableFact]    public async Task GetOrgEhrRecords_WithValidOrgId_ShouldReturnRecords()    {        await AuthenticateAsDoctorAsync(EhrClient);        // Use seed organization ID        var orgId = TestSeedData.HospitalAOrgId;                var response = await GetWithRetryAsync(EhrClient, ApiEndpoints.Ehr.OrgRecords(orgId));        Assert.Equal(HttpStatusCode.OK, response.StatusCode);                var json = await ReadJsonResponseAsync(response);        Assert.True(json.ValueKind == JsonValueKind.Array, "Should return array of records");    }}
